import{_ as t,o as n,c as i,ag as e}from"./chunks/framework.Vng7Hdlh.js";const m=JSON.parse('{"title":"Organizations","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/organizations.md","filePath":"admin-ui/organizations.md"}'),o={name:"admin-ui/organizations.md"};function r(d,a,s,g,l,c){return n(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="organizations" tabindex="-1">Organizations <a class="header-anchor" href="#organizations" aria-label="Permalink to &quot;Organizations&quot;">​</a></h1><p>The Organizations page manages Keycloak organizations within your realm. Organizations represent healthcare entities such as hospitals, clinics, or departments, and allow grouping users with shared branding and access policies.</p><h2 id="accessing" tabindex="-1">Accessing <a class="header-anchor" href="#accessing" aria-label="Permalink to &quot;Accessing&quot;">​</a></h2><p>Navigate to <strong>Organizations</strong> in the admin sidebar.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="organization-list" tabindex="-1">Organization List <a class="header-anchor" href="#organization-list" aria-label="Permalink to &quot;Organization List&quot;">​</a></h3><p>The main view displays all organizations with:</p><ul><li>Organization name and domain</li><li>Member count</li><li>Quick actions (edit, delete)</li><li>Search by name or domain</li></ul><h3 id="creating-an-organization" tabindex="-1">Creating an Organization <a class="header-anchor" href="#creating-an-organization" aria-label="Permalink to &quot;Creating an Organization&quot;">​</a></h3><p>Click <strong>Add Organization</strong> to create a new organization:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Display name of the organization</td></tr><tr><td><strong>Domains</strong></td><td>Email domains associated with this organization</td></tr><tr><td><strong>Description</strong></td><td>Optional description</td></tr><tr><td><strong>Attributes</strong></td><td>Custom key-value attributes</td></tr></tbody></table><h3 id="editing-an-organization" tabindex="-1">Editing an Organization <a class="header-anchor" href="#editing-an-organization" aria-label="Permalink to &quot;Editing an Organization&quot;">​</a></h3><p>Click an organization to open the edit dialog with two tabs:</p><h4 id="general-tab" tabindex="-1">General Tab <a class="header-anchor" href="#general-tab" aria-label="Permalink to &quot;General Tab&quot;">​</a></h4><ul><li>Update name, domains, description, and attributes</li><li>View and manage organization metadata</li></ul><h4 id="branding-tab" tabindex="-1">Branding Tab <a class="header-anchor" href="#branding-tab" aria-label="Permalink to &quot;Branding Tab&quot;">​</a></h4><ul><li>Configure organization-specific branding that overrides the global brand settings</li><li>Set custom logo URL, name, website, and portal details</li><li>Organization branding is used in the SMART User-Access Brand Bundle to differentiate sub-organizations</li></ul><h3 id="member-management" tabindex="-1">Member Management <a class="header-anchor" href="#member-management" aria-label="Permalink to &quot;Member Management&quot;">​</a></h3><p>Within an organization, you can manage membership:</p><ul><li><strong>View members</strong> — list all users belonging to the organization</li><li><strong>Add member</strong> — assign an existing Keycloak user to the organization</li><li><strong>Remove member</strong> — revoke a user&#39;s organization membership</li></ul><p>Members inherit the organization&#39;s branding and any organization-scoped access policies.</p><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/organizations/</code></td><td>List organizations (with search and pagination)</td></tr><tr><td><code>GET</code></td><td><code>/admin/organizations/count</code></td><td>Get organization count</td></tr><tr><td><code>GET</code></td><td><code>/admin/organizations/:orgId</code></td><td>Get organization details</td></tr><tr><td><code>POST</code></td><td><code>/admin/organizations/</code></td><td>Create organization</td></tr><tr><td><code>PUT</code></td><td><code>/admin/organizations/:orgId</code></td><td>Update organization</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/organizations/:orgId</code></td><td>Delete organization</td></tr><tr><td><code>GET</code></td><td><code>/admin/organizations/:orgId/members</code></td><td>List organization members</td></tr><tr><td><code>POST</code></td><td><code>/admin/organizations/:orgId/members</code></td><td>Add member to organization</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/organizations/:orgId/members/:userId</code></td><td>Remove member</td></tr><tr><td><code>GET</code></td><td><code>/admin/organizations/:orgId/branding</code></td><td>Get organization branding</td></tr><tr><td><code>PUT</code></td><td><code>/admin/organizations/:orgId/branding</code></td><td>Update organization branding</td></tr></tbody></table><h2 id="relationship-to-branding" tabindex="-1">Relationship to Branding <a class="header-anchor" href="#relationship-to-branding" aria-label="Permalink to &quot;Relationship to Branding&quot;">​</a></h2><p>Organization branding integrates with the SMART 2.2.0 User-Access Brand Bundle. When an organization has custom branding configured, it appears as a separate brand entry in the published bundle, allowing patient apps to display the correct logo and portal link for each sub-organization.</p><p>See <a href="./branding">Brand Management</a> for global branding configuration.</p>',26)])])}const b=t(o,[["render",r]]);export{m as __pageData,b as default};
